;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@command title="Which button will you press?" cancel=true
@select text="Ｂ１" exp='tf.result = ["牢獄Ｂ１", "up"]'
@select text="Ｂ２" exp='tf.result = ["牢獄Ｂ２", "up"]'
@select text="Ｂ４" exp='tf.result = ["牢獄Ｂ４", "down"]'
@select text="No" exp='tf.result = []'
[ask]
@elevator map=&'tf.result[0]' lift=&'tf.result[1]' cond='tf.result.count > 0'

